/**
 * 生成 CSV 表头
 */
function generateCSVHeader(questions) {
  const header = ['提交时间', '学生IP', '学生姓名', '学号', ...questions.map(q => q.title), '状态'];
  return header.map(escapeCSVField).join(',');
}

/**
 * 将提交数据格式化为 CSV 行
 * 注意：学生姓名和学号由服务器自动添加，客户端只提交答案数据
 */
function formatSubmissionAsCSV(submission, questions) {
  // 准备时间戳（使用 ISO 格式避免逗号）
  const timestamp = new Date(submission.timestamp).toISOString();

  // 准备答案数据
  const answers = questions.map(q => {
    const answer = submission.answers[q.id];
    return formatAnswerValue(answer, q.type);
  });

  // 组合数据行（学生姓名和学号留空，由服务器填充）
  const row = [timestamp, '',
  // 学生IP - 由服务器根据连接IP填充
  '',
  // 学生姓名 - 由服务器根据座位表填充
  '',
  // 学号 - 由服务器根据座位表填充
  ...answers, submission.status];

  // 转义并返回
  return row.map(escapeCSVField).join(',');
}

/**
 * 格式化答案值为字符串
 */
function formatAnswerValue(value, type) {
  if (value === null || value === undefined || value === '') {
    return '';
  }
  switch (type) {
    case 'multiple':
    case 'ranking':
      return Array.isArray(value) ? value.join(';') : String(value);
    case 'text':
      return String(value).replace(/[\r\n]+/g, ' ').trim();
    default:
      return String(value);
  }
}

/**
 * 转义 CSV 字段
 */
function escapeCSVField(field) {
  const str = String(field || '');
  if (str.includes(',') || str.includes('\n') || str.includes('"')) {
    return `"${str.replace(/"/g, '""')}"`;
  }
  return str;
}

